    {
      "n": 28,
      "column": "left",
      "text": "Un zitti no teem bija pahr\n ta Ammata Rihkeem eezelti/ un\nneffe tohs skaititus eeksha un\nahra.\n"
    },
    {
      "n": 29,
      "column": "left",
      "text": "Un zitti no teem bija pahr\nteein Rihkeem/ un pahr wiʃeein\nʃwehteem Rihkeem eezelti : Un\npahr teem Kweefchu - Milteem /\nun Wihnu/ yn Eji/ un Wihra-\nfu/ un dahrgahin Sahlehem.\n"
    },
    {
      "n": 30,
      "column": "left",
      "text": "Un no to Preestern Behr-\nneem fataifija zitti tahs dahrgas\nKwehpja-Sahles.\n"
    },
    {
      "n": 31,
      "column": "left",
      "text": "Un Matattjami no teem\nLewiteem/ kas Salluma ta Ko-\nritera pirmdsimunnis bija / bi-\nja to Panmu Darbs ustizzehts.\n"
    },
    {
      "n": 32,
      "column": "left",
      "text": "Un no to Käntitern Behr-\nneem winnu Brahteem bija zitti\npahr to Maises Gataifischann\neezelti/ ka ta ik Swehdeenass tap-\ntu fataifita.\n"
    },
    {
      "n": 33,
      "column": "left",
      "text": "Un fchee irr tee Dseedata-\nji/ Wirfneeki pahr teem Tehwu\nNamimeem/starp teem Lewiteem/\nfeuwiʃcki pahr teem Schkirsteem\neezelti/ jo Deenä un Nakti bija\nteem tur Darba.\n"
    },
    {
      "n": 34,
      "column": "left",
      "text": "Schee irr tee Wirfneeki\npahr teem Tehwu Namimeem /\nstarp teem Lewiteem faru Rad-\ndu Wirfneeki. Schee dsihwoja\nJerusaleme.\n"
    },
    {
      "n": 35,
      "column": "left",
      "text": "Bet Gibeona dsihwoja\nIcjele Gibeona Tehws/ un win-\nna Seervai bija Maeka Wahrdä.\n"
    },
    {
      "n": 36,
      "column": "left",
      "text": "Un winna pirmdsimunte\nDchis bija Abdons/ un Jurs/ un\n"
    },
    {
      "n": 28,
      "column": "right",
      "text": "Ris/ un Vääls/ un Ners/\nNadabs.\n"
    },
    {
      "n": 37,
      "column": "right",
      "text": "Un Gedors/ un Aäj\nun Sakartjas/ un Miklots.\n"
    },
    {
      "n": 38,
      "column": "right",
      "text": "Un Miklots dsemdin\nStmeatni / fchee arridsan d\nwoja faweem Brahteem pr\nJerusaleme pee faweem B\nkeem.\n"
    },
    {
      "n": 39,
      "column": "right",
      "text": "Un Ners dsemdinaja\nfu / un Ris dsemdinaja Sau\nUn Sauls dsemdinaja Jona-\nni/ un Malkisuü/ un Abina-\nbu/ un Esbäilu.\n"
    },
    {
      "n": 40,
      "column": "right",
      "text": "Un Jonatana Dehis b\nMeribääls. Un Meribääls dse-\ndinaja Miku.\n"
    },
    {
      "n": 41,
      "column": "right",
      "text": "Un Mikus Behrni bij\nPitons un Meleks/ un Taärij\n"
    },
    {
      "n": 42,
      "column": "right",
      "text": "Un Akas dsemdinaja\nern. Un Jaerus dsemdinaja\nlemetu/ un Asmawetu/ un Si-\nru. Un Simrus dsemdin-\nMozu.\n"
    },
    {
      "n": 43,
      "column": "right",
      "text": "Un Mozus dsemdin-\nBineü/ ta Dehis bija Rewaju\nta Dehis bija Eleasus/ ta De-\nbija Azels.\n"
    },
    {
      "n": 44,
      "column": "right",
      "text": "Un Azelam bija fe-\nDehti/ un fchee irr winnu Wah-\ndi/ Afrikans/ Bokrus/ un J\nmaels/ un Searijus/ un Oba-\njus/ nn Anans/ fchee irr Aze-\nBehrni.\n"
    }
  ],
